const express = require('express');
const fetch = require('node-fetch');
const { URL } = require('url');
const net = require('net');
const dns = require('dns');
const { promisify } = require('util');

const dnsResolve = promisify(dns.resolve4);

const app = express();
app.use(express.json({ limit: '1mb' }));

// Configuration
const PORT = process.env.PORT || 3000;
const REQUEST_TIMEOUT_MS = parseInt(process.env.REQUEST_TIMEOUT_MS, 10) || 10000;
const MAX_RESPONSE_SIZE = parseInt(process.env.MAX_RESPONSE_SIZE, 10) || 5 * 1024 * 1024; // 5MB
const ALLOWED_PROTOCOLS = ['https:'];
const MAX_REDIRECTS = 3;

// Rate limiting (simple in-memory, use Redis in production)
const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW_MS = 60000;
const RATE_LIMIT_MAX_REQUESTS = 60;

function rateLimit(clientId) {
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;

  if (!rateLimitMap.has(clientId)) {
    rateLimitMap.set(clientId, []);
  }

  const timestamps = rateLimitMap.get(clientId).filter(t => t > windowStart);
  timestamps.push(now);
  rateLimitMap.set(clientId, timestamps);

  return timestamps.length <= RATE_LIMIT_MAX_REQUESTS;
}

// Clean up rate limit map periodically
setInterval(() => {
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;
  for (const [key, timestamps] of rateLimitMap.entries()) {
    const filtered = timestamps.filter(t => t > windowStart);
    if (filtered.length === 0) {
      rateLimitMap.delete(key);
    } else {
      rateLimitMap.set(key, filtered);
    }
  }
}, RATE_LIMIT_WINDOW_MS);

// Blocklist of private/internal IP ranges (SSRF protection)
function isPrivateIP(ip) {
  // Check for IPv4 private ranges
  const parts = ip.split('.').map(Number);
  if (parts.length !== 4 || parts.some(p => isNaN(p))) {
    return true; // Block anything we can't parse
  }

  // 10.0.0.0/8
  if (parts[0] === 10) return true;
  // 172.16.0.0/12
  if (parts[0] === 172 && parts[1] >= 16 && parts[1] <= 31) return true;
  // 192.168.0.0/16
  if (parts[0] === 192 && parts[1] === 168) return true;
  // 127.0.0.0/8 (loopback)
  if (parts[0] === 127) return true;
  // 169.254.0.0/16 (link-local, includes cloud metadata endpoints)
  if (parts[0] === 169 && parts[1] === 254) return true;
  // 0.0.0.0/8
  if (parts[0] === 0) return true;
  // 100.64.0.0/10 (carrier-grade NAT)
  if (parts[0] === 100 && parts[1] >= 64 && parts[1] <= 127) return true;
  // 192.0.0.0/24
  if (parts[0] === 192 && parts[1] === 0 && parts[2] === 0) return true;
  // 198.18.0.0/15
  if (parts[0] === 198 && (parts[1] === 18 || parts[1] === 19)) return true;
  // 224.0.0.0/4 (multicast)
  if (parts[0] >= 224) return true;

  return false;
}

// Blocked hostnames
const BLOCKED_HOSTNAMES = new Set([
  'metadata.google.internal',
  'metadata.google',
  'metadata',
  'localhost',
  'instance-data',
]);

async function validateUrl(urlString) {
  let parsed;
  try {
    parsed = new URL(urlString);
  } catch {
    throw new Error('Invalid URL format');
  }

  // Protocol check
  if (!ALLOWED_PROTOCOLS.includes(parsed.protocol)) {
    throw new Error(`Protocol not allowed: ${parsed.protocol}. Only HTTPS is permitted.`);
  }

  // Block certain hostnames
  const hostname = parsed.hostname.toLowerCase();
  if (BLOCKED_HOSTNAMES.has(hostname)) {
    throw new Error('Blocked hostname');
  }

  // Block IP addresses used directly in URL
  if (net.isIP(hostname)) {
    if (isPrivateIP(hostname)) {
      throw new Error('Private/internal IP addresses are not allowed');
    }
    return parsed;
  }

  // DNS resolution check to prevent DNS rebinding / SSRF via DNS
  try {
    const addresses = await dnsResolve(hostname);
    for (const addr of addresses) {
      if (isPrivateIP(addr)) {
        throw new Error('URL resolves to a private/internal IP address');
      }
    }
  } catch (err) {
    if (err.message.includes('private') || err.message.includes('internal')) {
      throw err;
    }
    throw new Error(`DNS resolution failed for hostname: ${hostname}`);
  }

  return parsed;
}

// Allowed headers to forward from the upstream response
const SAFE_RESPONSE_HEADERS = new Set([
  'content-type',
  'content-length',
  'content-encoding',
  'cache-control',
  'etag',
  'last-modified',
  'date',
]);

// Allowed request headers to forward
const SAFE_REQUEST_HEADERS = new Set([
  'accept',
  'accept-language',
  'content-type',
  'content-length',
]);

function sanitizeRequestHeaders(headers) {
  const sanitized = {};
  if (headers && typeof headers === 'object') {
    for (const [key, value] of Object.entries(headers)) {
      const lowerKey = key.toLowerCase();
      if (SAFE_REQUEST_HEADERS.has(lowerKey) && typeof value === 'string') {
        // Prevent header injection
        sanitized[lowerKey] = value.replace(/[\r\n]/g, '');
      }
    }
  }
  return sanitized;
}

// API key authentication middleware
function authenticate(req, res, next) {
  const apiKey = req.headers['x-api-key'];
  const expectedKey = process.env.WEBHOOK_PROXY_API_KEY;

  if (!expectedKey) {
    console.error('WEBHOOK_PROXY_API_KEY environment variable is not set');
    return res.status(500).json({ error: 'Server misconfiguration' });
  }

  if (!apiKey || apiKey.length !== expectedKey.length) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  // Constant-time comparison
  const crypto = require('crypto');
  if (!crypto.timingSafeEqual(Buffer.from(apiKey), Buffer.from(expectedKey))) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  next();
}

