// Main webhook proxy endpoint
app.post('/proxy', authenticate, async (req, res) => {
  const clientIp = req.ip || req.connection.remoteAddress || 'unknown';

  // Rate limiting
  if (!rateLimit(clientIp)) {
    return res.status(429).json({ error: 'Rate limit exceeded. Try again later.' });
  }

  const { url, method, headers, body } = req.body;

  if (!url || typeof url !== 'string') {
    return res.status(400).json({ error: 'Missing or invalid "url" parameter' });
  }

  // Validate HTTP method
  const allowedMethods = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'];
  const requestMethod = (method || 'GET').toUpperCase();
  if (!allowedMethods.includes(requestMethod)) {
    return res.status(400).json({ error: `Method not allowed: ${requestMethod}` });
  }

  try {
    // Validate and sanitize URL (SSRF protection)
    const validatedUrl = await validateUrl(url);

    const sanitizedHeaders = sanitizeRequestHeaders(headers);

    // Build fetch options
    const fetchOptions = {
      method: requestMethod,
      headers: {
        ...sanitizedHeaders,
        'User-Agent': 'WebhookProxy/1.0',
      },
      timeout: REQUEST_TIMEOUT_MS,
      redirect: 'manual', // Handle redirects manually for SSRF protection
      size: MAX_RESPONSE_SIZE,
    };

    // Attach body for methods that support it
    if (['POST', 'PUT', 'PATCH'].includes(requestMethod) && body !== undefined) {
      if (typeof body === 'string') {
        fetchOptions.body = body;
      } else if (typeof body === 'object') {
        fetchOptions.body = JSON.stringify(body);
        if (!sanitizedHeaders['content-type']) {
          fetchOptions.headers['content-type'] = 'application/json';
        }
      }
    }

    let response;
    let currentUrl = validatedUrl.href;
    let redirectCount = 0;

    // Manual redirect following with SSRF checks on each redirect
    while (true) {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
      fetchOptions.signal = controller.signal;

      try {
        response = await fetch(currentUrl, fetchOptions);
      } finally {
        clearTimeout(timeoutId);
      }

      if ([301, 302, 303, 307, 308].includes(response.status)) {
        redirectCount++;
        if (redirectCount > MAX_REDIRECTS) {
          return res.status(502).json({ error: 'Too many redirects' });
        }

        const location = response.headers.get('location');
        if (!location) {
          return res.status(502).json({ error: 'Redirect without location header' });
        }

        // Resolve relative URLs
        const redirectUrl = new URL(location, currentUrl);

        // Validate redirect target for SSRF
        await validateUrl(redirectUrl.href);
        currentUrl = redirectUrl.href;

        // For 303, change method to GET
        if (response.status === 303) {
          fetchOptions.method = 'GET';
          delete fetchOptions.body;
        }

        continue;
      }

      break;
    }

    // Read response body with size limit
    const responseBuffer = await response.buffer();

    if (responseBuffer.length > MAX_RESPONSE_SIZE) {
      return res.status(502).json({ error: 'Response too large' });
    }

    // Forward safe headers
    const responseHeaders = {};
    for (const [key, value] of response.headers.entries()) {
      if (SAFE_RESPONSE_HEADERS.has(key.toLowerCase())) {
        responseHeaders[key] = value;
      }
    }

    // Set security headers on our response
    res.set({
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'Content-Security-Policy': "default-src 'none'",
    });

    // Return proxied response
    res.status(200).json({
      statusCode: response.status,
      headers: responseHeaders,
      body: responseBuffer.toString('utf-8'),
    });

    console.log(JSON.stringify({
      event: 'proxy_request',
      clientIp,
      targetUrl: validatedUrl.origin + validatedUrl.pathname, // Don't log query params
      method: requestMethod,
      responseStatus: response.status,
      responseSize: responseBuffer.length,
      timestamp: new Date().toISOString(),
    }));

  } catch (err) {
    const isTimeout = err.name === 'AbortError' || err.type === 'request-timeout';

    if (isTimeout) {
      return res.status(504).json({ error: 'Request to target URL timed out' });
    }

    // Don't leak internal error details
    const safeMessages = [
      'Invalid URL format',
      'Protocol not allowed',
      'Blocked hostname',
      'Private/internal IP addresses are not allowed',
      'URL resolves to a private/internal IP address',
      'DNS resolution failed',
      'Too many redirects',
      'Response too large',
    ];

    const isSafeMessage = safeMessages.some(msg => err.message && err.message.includes(msg));

    console.error(JSON.stringify({
      event: 'proxy_error',
      clientIp,
      error: err.message,
      timestamp: new Date().toISOString(),
    }));

    if (isSafeMessage) {
      return res.status(400).json({ error: err.message });
    }

    return res.status(502).json({ error: 'Failed to fetch the target URL' });
  }
});

// Catch-all for undefined routes
